INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (13, 103311, "", "", 870, "", 1033501039, "", 1033501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 103311, "", 1, "急に牛乳と卵が欲しいっつうから\n何かと思ったけんど、まさか\nオラのためにこんな立派なケーキ\n用意してくれてただなんてな！", 0, 1033501040, 6, 1033501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1033501041, "", 1033501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1033501", "", "", "vo_adv_1033501_001", "", 1033501042, 0, 1033501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 103311, "", 1, "オラの食材とあんちゃんの腕……\nこれは二人の共同作業ってことに……\nな、なんでもねぇ！\n気にしねぇでけろ！", 0, 1033501043, 5, 1033501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1033501044, "", 1033501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1033501", "", "", "vo_adv_1033501_002", "", 1033501045, 0, 1033501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 103311, "", 1, "それにしても食べるのが\nもったいねぇいいケーキだなぁ……\nでも食べなきゃ食べねぇで\nもったいねぇよなぁ……", 0, 1033501046, 6, 1033501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1033501047, "", 1033501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1033501", "", "", "vo_adv_1033501_003", "", 1033501048, 0, 1033501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 103311, "", 1, "うーん……\nオラ一人で食べるのも申し訳ねぇし\nエリザベスパークのみんなで\n食べるべか！", 0, 1033501049, 6, 1033501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1033501050, "", 1033501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1033501", "", "", "vo_adv_1033501_004", "", 1033501051, 0, 1033501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 103311, "", 1, "みんなで過ごすのがオラにとって\n最高の誕生日だべ！\nあんがとな、あんちゃん！", 0, 1033501052, 6, 1033501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1033501053, "", 1033501, "", "");
