INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 103411, "", 1, "なんでって、それは……\nキミがお祝いに来てくれるかも、\nなんて思ってたから……", 0, 1034501046, 5, 1034501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1034501047, "", 1034501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1034501", "", "", "vo_adv_1034501_003", "", 1034501048, 0, 1034501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 103411, "", 1, "だから、今日は麦しゅわは封印よ。\n麦しゅわもありの大人な誕生日は、\nキミが大人になってから……ね？", 0, 1034501049, 5, 1034501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1034501050, "", 1034501, "", "");
