INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 104611, "", 1, "にゃはは～！\n誕生日のお祝いしてくれて\nどうもありがとにゃ！", 0, 1046501040, 6, 1046501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1046501041, "", 1046501, "", "");
