INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (13, 105111, "", "", 870, "", 1051501039, "", 1051501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 105111, "", 1, "誕生日を祝ってくれてありがとう。\nいくつになってもお祝いして\nもらえるのはうれしいものね。", 0, 1051501040, 7, 1051501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1051501041, "", 1051501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1051501", "", "", "vo_adv_1051501_001", "", 1051501042, 0, 1051501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 105111, "", 1, "え、このケーキ君の手作りなの？\nなによ至れり尽くせりじゃない。", 0, 1051501043, 4, 1051501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1051501044, "", 1051501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1051501", "", "", "vo_adv_1051501_002", "", 1051501045, 0, 1051501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 105111, "", 1, "ここまでしてもらったら大人しく\n祝ってもらうしかないわね。\nいくら私でも時と場合は\nちゃんとわきまえるわよ。", 0, 1051501046, 6, 1051501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1051501047, "", 1051501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1051501", "", "", "vo_adv_1051501_003", "", 1051501048, 0, 1051501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 105111, "", 1, "でも、もらってばかりなのは\n性に合わないから、今度お返しに\n体が丈夫になる薬でも\nプレゼントするわ。", 0, 1051501049, 6, 1051501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1051501050, "", 1051501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1051501", "", "", "vo_adv_1051501_004", "", 1051501051, 0, 1051501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 105111, "", 1, "君には健康でいてもらって\nまた誕生日を祝ってもらいたいもの。\nまあ、薬が効きすぎて\n変なことになってもご愛敬ね。", 0, 1051501052, 6, 1051501, 0, 1);
