INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 105711, "", 1, "ゆっくりでいいからがんばって\n騎空団として成長して……\nいつかは蒼い空を自由に旅したいな。\nもちろん、その時はあなたも一緒だよ！", 0, 1057501049, 5, 1057501, 0, 1);
