INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (13, 111011, "", "", 870, "", 1110501039, "", 1110501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 111011, "", 1, "ほわあああぁぁ何この蝋燭！？\n思わず知的興奮で吹き消してしまったが\n怪しい残り香、興味深ぁ～！\n鼻腔から学び入ってくる～！", 0, 1110501040, 5, 1110501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1110501041, "", 1110501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1110501", "", "", "vo_adv_1110501_001", "", 1110501042, 0, 1110501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 111011, "", 1, "この蝋燭は、もしや君が作ったのか？\nなに、精油にそんな希少な成分を？\nわざわざぼくの誕生日を祝うために？\n後輩……君という子は……！", 0, 1110501043, 4, 1110501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1110501044, "", 1110501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1110501", "", "", "vo_adv_1110501_002", "", 1110501045, 0, 1110501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 111011, "", 1, "しかし蝋燭はいいが、この土台部分──\nいや、バースデーケーキとかいう祝祭の\n文化か。ううむ気持ちは有難いが、\n食の細いぼくには若干拷問サイズだ……", 0, 1110501046, 4, 1110501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1110501047, "", 1110501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1110501", "", "", "vo_adv_1110501_003", "", 1110501048, 0, 1110501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 111011, "", 1, "ややっ？　よくよく見ればこの土台、\nケーキなのはほんの一部分だけで、\n大半はよく出来た模造品じゃあないか！\nな、なんと配慮の行き届いた……！", 0, 1110501049, 5, 1110501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1110501050, "", 1110501, "", "");
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (21, "vo_adv_1110501", "", "", "vo_adv_1110501_004", "", 1110501051, 0, 1110501, "", 0);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (11, 111011, "", 1, "是非もなし。\n端的に言えば、先輩ちょっと感激した。\n今宵は飲めや食えやの大騒ぎだ。\n朝まで踊り明かすぜ同志、ヒャッハー！", 0, 1110501052, 5, 1110501, 0, 1);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (91, 0, "", "", "", "", 1110501053, "", 1110501, "", "");
